import type { Database } from '../types';
import { loadDatabase, saveWithRetry } from './githubStore';

type Listener = () => void;

class Store {
  private data: Database | null = null;
  private listeners: Listener[] = [];
  private loading = false;
  // Cola de guardados: cada mutate() se encadena al anterior, así nunca
  // hay dos peticiones de guardado "en vuelo" al mismo tiempo — evita el
  // falso "alguien más guardó un cambio" cuando en realidad es el mismo
  // usuario escaneando muy rápido y dos guardados se cruzan entre sí.
  private colaGuardado: Promise<Database> = Promise.resolve(null as unknown as Database);

  get current(): Database | null {
    return this.data;
  }

  subscribe(fn: Listener): () => void {
    this.listeners.push(fn);
    return () => {
      this.listeners = this.listeners.filter((l) => l !== fn);
    };
  }

  private notify() {
    this.listeners.forEach((l) => l());
  }

  async load(force = false): Promise<Database> {
    if (this.data && !force) return this.data;
    if (this.loading) {
      // Espera a que la carga en curso termine en vez de disparar otra.
      await new Promise((r) => setTimeout(r, 150));
      return this.load(force);
    }
    this.loading = true;
    try {
      const { data } = await loadDatabase();
      this.data = data;
      this.notify();
      return data;
    } finally {
      this.loading = false;
    }
  }

  /**
   * Aplica una mutación y la persiste en GitHub. Si hay conflicto de
   * concurrencia (alguien más guardó primero), reintenta con datos
   * frescos — ver githubStore.saveWithRetry. Los guardados siempre se
   * procesan en fila (uno espera a que termine el anterior).
   */
  async mutate(mutate: (db: Database) => Database, commitMessage: string): Promise<Database> {
    const tarea = this.colaGuardado.then(() => saveWithRetry(mutate, commitMessage));
    // Si esta tarea específica falla, no debe tumbar la cola para las
    // siguientes — cada quien maneja su propio error.
    this.colaGuardado = tarea.catch(() => this.data as Database);
    const result = await tarea;
    this.data = result;
    this.notify();
    return result;
  }
}

export const store = new Store();
